// ══════════════════════════════════════════════════════════════
// Phase 1.1 — Runtime backfill: unitId FK on all transaction lines
// Phase 2   — Optimistic locking: version field on inventory
// ══════════════════════════════════════════════════════════════

/** Product → default unit mapping for backfill */
const PRODUCT_UNIT_MAP: Record<string, { unitId: string; unitAbbr: string; unitName: string; conversionFactor: number }> = {
  P001: { unitId: "PUC-002", unitAbbr: "Sac", unitName: "Sac (50kg)", conversionFactor: 50 },
  P002: { unitId: "PUC-090", unitAbbr: "Bar", unitName: "Barre (12m)", conversionFactor: 1 },
  P003: { unitId: "PUC-100", unitAbbr: "Pce", unitName: "Pièce", conversionFactor: 1 },
  P004: { unitId: "DEFAULT-P004", unitAbbr: "T", unitName: "Tonne", conversionFactor: 1 },
  P005: { unitId: "DEFAULT-P005", unitAbbr: "Pal", unitName: "Palette (200)", conversionFactor: 1 },
  P006: { unitId: "DEFAULT-P006", unitAbbr: "Bar", unitName: "Barre (4m)", conversionFactor: 1 },
  P007: { unitId: "DEFAULT-P007", unitAbbr: "Seau", unitName: "Seau (25L)", conversionFactor: 1 },
  P008: { unitId: "DEFAULT-P008", unitAbbr: "Sac", unitName: "Sac (40kg)", conversionFactor: 1 },
  P009: { unitId: "PUC-011", unitAbbr: "Sac", unitName: "Sac (50kg)", conversionFactor: 50 },
  P010: { unitId: "PUC-021", unitAbbr: "Bid", unitName: "Bidon (5L)", conversionFactor: 5 },
  P011: { unitId: "PUC-031", unitAbbr: "Ctn", unitName: "Carton (24)", conversionFactor: 24 },
  P012: { unitId: "PUC-061", unitAbbr: "Sac", unitName: "Sac (50kg)", conversionFactor: 50 },
  P013: { unitId: "PUC-051", unitAbbr: "Ctn", unitName: "Carton (12)", conversionFactor: 12 },
  P014: { unitId: "PUC-041", unitAbbr: "Ctn", unitName: "Carton (20)", conversionFactor: 20 },
  P015: { unitId: "DEFAULT-P015", unitAbbr: "Sac", unitName: "Sac (5kg)", conversionFactor: 1 },
  P016: { unitId: "PUC-071", unitAbbr: "Ctn", unitName: "Carton (48)", conversionFactor: 48 },
  P017: { unitId: "PUC-080", unitAbbr: "Pce", unitName: "Pièce", conversionFactor: 1 },
  P018: { unitId: "DEFAULT-P018", unitAbbr: "Pce", unitName: "Pièce", conversionFactor: 1 },
  P020: { unitId: "DEFAULT-P020", unitAbbr: "Pce", unitName: "Pièce", conversionFactor: 1 },
  P023: { unitId: "DEFAULT-P023", unitAbbr: "Pce", unitName: "Pièce", conversionFactor: 1 },
  P024: { unitId: "DEFAULT-P024", unitAbbr: "Pce", unitName: "Pièce", conversionFactor: 1 },
};

function backfillUnit<T extends { productId: string; unitId?: string; unitAbbr?: string; unitName?: string; conversionFactor?: number; baseQty?: number }>(
  line: T, qtyField: keyof T
): void {
  if (line.unitId) return; // already backfilled
  const u = PRODUCT_UNIT_MAP[line.productId];
  if (!u) return;
  line.unitId = u.unitId;
  line.unitAbbr = u.unitAbbr;
  line.unitName = u.unitName;
  line.conversionFactor = u.conversionFactor;
  line.baseQty = Math.round((line[qtyField] as number) * u.conversionFactor * 10000) / 10000;
}

// Phase 1.1a — Backfill GRN lines
grns.forEach(grn => grn.lines.forEach(line => backfillUnit(line, "receivedQty")));

// Phase 1.1b — Backfill SO lines
salesOrders.forEach(so => so.lines.forEach(line => backfillUnit(line, "orderedQty")));

// Phase 1.1c — Backfill Stock Adjustments
stockAdjustments.forEach(adj => {
  if (!adj.unitId) {
    const u = PRODUCT_UNIT_MAP[adj.productId];
    if (u) {
      adj.unitId = u.unitId;
      adj.unitAbbr = u.unitAbbr;
      adj.unitName = u.unitName;
      adj.conversionFactor = u.conversionFactor;
      adj.baseQty = Math.round(adj.qty * u.conversionFactor * 10000) / 10000;
    }
  }
});

// Phase 2 — Add version=1 to all inventory rows (optimistic locking)
inventory.forEach(item => { if (item.version == null) item.version = 1; });
